def predict(triples: list[Triple]) -> str:
    """
    Convert a list of food‑related triples into a single fluent sentence.
    """
    if not triples:
        return ""

    # Group triples by subject
    subject_map = {}
    for t in triples:
        if t.subject not in subject_map:
            subject_map[t.subject] = []
        subject_map[t.subject].append((t.predicate, t.object))

    # Find the main subject (most triples or first one)
    main_subject = max(subject_map.keys(), key=lambda s: len(subject_map[s]))

    # Build predicate to clause mapping
    def get_clause(predicate, obj, subject):
        # Clean object value (remove quotes if present)
        clean_obj = obj.strip('"')

        if predicate == "country":
            return f"from {clean_obj}"
        elif predicate == "region":
            return f"from the {clean_obj} region"
        elif predicate == "mainIngredient":
            return f"with {clean_obj} as the main ingredient"
        elif predicate == "ingredient":
            return f"containing {clean_obj}"
        elif predicate == "dishVariation":
            return f"with variations like {clean_obj}"
        elif predicate == "course":
            return f"served as a {clean_obj}"
        elif predicate == "servingTemperature" or predicate == "served":
            return f"typically {clean_obj}"
        elif predicate == "servingSize":
            return f"with a serving size of {clean_obj}"
        elif predicate == "carbohydrate":
            return f"containing {clean_obj} carbohydrates"
        elif predicate == "fat":
            return f"containing {clean_obj} fat"
        elif predicate == "protein":
            return f"containing {clean_obj} protein"
        elif predicate == "division":
            return f"of the {clean_obj} division"
        elif predicate == "family":
            return f"in the {clean_obj} family"
        elif predicate == "order":
            return f"under the {clean_obj} order"
        elif predicate == "genus":
            return f"of the {clean_obj} genus"
        elif predicate == "class":
            return f"classified as a {clean_obj}"
        elif predicate == "alternativeName":
            return f"also known as {clean_obj}"
        elif predicate == "creator" or predicate == "creatorOfDish":
            return f"created by {clean_obj}"
        elif predicate == "year":
            return f"introduced in {clean_obj}"
        elif predicate == "related":
            return f"related to {clean_obj}"
        elif predicate == "similarDish":
            return f"similar to {clean_obj}"
        elif predicate == "isPartOf":
            return f"part of {clean_obj}"
        elif predicate == "capital":
            return f"where the capital is {clean_obj}"
        elif predicate == "leader":
            return f"led by {clean_obj}"
        elif predicate == "currency":
            return f"using {clean_obj} as currency"
        elif predicate == "demonym":
            return f"with {clean_obj}"
        elif predicate == "ethnicGroup":
            return f"home to {clean_obj}"
        elif predicate == "language":
            return f"where {clean_obj} is spoken"
        elif predicate == "officialLanguage":
            return f"with {clean_obj} as the official language"
        elif predicate == "leaderTitle":
            return f"with the leader title {clean_obj}"
        elif predicate == "foundationPlace":
            return f"founded in {clean_obj}"
        else:
            return f"with {predicate} {clean_obj}"

    # Collect all clauses from the main subject
    clauses = []

    if main_subject in subject_map:
        predicates = subject_map[main_subject]
        for pred, obj in predicates:
            clause = get_clause(pred, obj, main_subject)
            clauses.append(clause)

    if not clauses:
        return f"{main_subject} is a food item."

    # Build the final sentence - join clauses with commas and 'and' for natural flow
    if len(clauses) == 1:
        return f"{main_subject} {clauses[0]}."
    elif len(clauses) == 2:
        return f"{main_subject} {clauses[0]} and {clauses[1]}."
    else:
        last_clause = clauses[-1]
        remaining = ", ".join(clauses[:-1])
        return f"{main_subject} {remaining}, and {last_clause}."

